sp_header_footer.css:
.idpbob-header {
    background-color: var(--carbon-ui-05);
    padding: var(--carbon-spacing-04) var(--carbon-spacing-06);
    box-shadow: 0 1px 2px rgba(0, 0, 0, 0.1);
}

.idpbob-header-brand {
    color: var(--carbon-text-04);
    font-size: 1.25rem;
    font-weight: 600;
    text-decoration: none;
}

.idpbob-header-brand:hover {
    color: var(--carbon-text-04);
    text-decoration: none;
}

.idpbob-header-nav {
    display: flex;
    align-items: center;
    gap: var(--carbon-spacing-05);
}

.idpbob-header-nav-item {
    color: var(--carbon-text-04);
    padding: var(--carbon-spacing-03) var(--carbon-spacing-04);
    text-decoration: none;
    transition: background-color 0.11s cubic-bezier(0.2, 0, 0.38, 0.9);
}

.idpbob-header-nav-item:hover {
    background-color: var(--carbon-hover-secondary);
    color: var(--carbon-text-04);
    text-decoration: none;
}

.idpbob-header-nav-item.active {
    background-color: var(--carbon-interactive-01);
    color: var(--carbon-text-04);
}

.idpbob-header-user {
    margin-left: auto;
    display: flex;
    align-items: center;
    gap: var(--carbon-spacing-03);
    color: var(--carbon-text-04);
}

.idpbob-header-user-avatar {
    width: 32px;
    height: 32px;
    border-radius: 50%;
    background-color: var(--carbon-interactive-01);
    display: flex;
    align-items: center;
    justify-content: center;
    color: var(--carbon-text-04);
    font-weight: 600;
}
